mapper.insert:
INSERT INTO buildings (
    build_name, build_time, build_section, build_state, build_capacity
) VALUES (
    #{buildName}, #{buildTime}, #{buildSection}, #{buildState}, #{buildCapacity}
)

mapper.delete:
DELETE FROM buildings

    build_name = #{buildName}
    
        AND build_time = #{buildTime}
    
    
        AND build_section = #{buildSection}

mapper.update:
UPDATE buildings
SET build_time = #{buildTime},
    build_section = #{buildSection},
    build_state = #{buildState},
    build_capacity = #{buildCapacity}
WHERE build_name = #{buildName}
AND build_time = #{buildTime}
AND build_section = #{buildSection}

mapper.select:
SELECT build_name, MAX(build_state) AS build_state, MAX(build_capacity) AS build_capacity, build_time, build_section FROM buildings
AND build_name LIKE CONCAT('%', #{buildName}, '%')
AND build_time = #{buildTime}
AND build_section = #{buildSection}
GROUP BY build_name, build_time, build_section
